4	describe("Game of Life", () => {
5	  it("should return empty grid when given empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single living cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells each having fewer than 2 neighbors", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block (2x2 square) unchanged as a still life", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result.sort()).toEqual(block.sort());
18	  });
19	  it("should keep a live cell with exactly 2 neighbors alive", () => {
20	    // Three cells in a row: (0,0), (1,0), (2,0). The center cell (1,0) has exactly 2 neighbors.
21	    const cells: [number, number][] = [[0, 0], [1, 0], [2, 0]];
22	    const result = nextGeneration(cells);
23	    expect(result).toContainEqual([1, 0]);
24	  });
25	  it("should keep a live cell with exactly 3 neighbors alive", () => {
26	    // L-shape: (0,0), (1,0), (0,1), (1,1). The cell (0,0) has exactly 3 neighbors.
27	    const cells: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
28	    const result = nextGeneration(cells);
29	    expect(result).toContainEqual([0, 0]);
30	  });
31	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
32	    // Plus/cross pattern: center (1,1) has 4 neighbors
33	    const cells: [number, number][] = [[1, 0], [0, 1], [1, 1], [2, 1], [1, 2]];
34	    const result = nextGeneration(cells);
35	    expect(result).not.toContainEqual([1, 1]);
36	  });
37	  it("should bring a dead cell with exactly 3 live neighbors to life (reproduction)", () => {
38	    // L-shape: (0,0), (1,0), (0,1). Dead cell (1,1) has exactly 3 live neighbors → becomes alive.
39	    const cells: [number, number][] = [[0, 0], [1, 0], [0, 1]];
40	    const result = nextGeneration(cells);
41	    expect(result).toContainEqual([1, 1]);
42	  });
43	  it.todo("should oscillate a blinker from vertical to horizontal");
44	});
